# -*- coding: utf-8 -*-
"""Jismoniy tarbiya - Mustaqil ishlar (15 mavzu)"""
import zipfile, datetime
TOPICS = []
def esc(t): return t.replace("&","&amp;").replace("<","&lt;").replace(">","&gt;").replace('"',"&quot;")
def run(text,bold=False,size=28,font="Times New Roman"):
    rpr='<w:rPr><w:rFonts w:ascii="%s" w:hAnsi="%s" w:cs="%s"/>'%(font,font,font)
    if bold: rpr+='<w:b/><w:bCs/>'
    rpr+='<w:sz w:val="%d"/><w:szCs w:val="%d"/></w:rPr>'%(size,size)
    return '<w:r>%s<w:t xml:space="preserve">%s</w:t></w:r>'%(rpr,esc(text))
def para(text,bold=False,size=28,align="both",indent_first=709,space_after=120,line=360,keep_next=False):
    ppr='<w:pPr>'
    if keep_next: ppr+='<w:keepNext/>'
    ppr+='<w:spacing w:after="%d" w:line="%d" w:lineRule="auto"/>'%(space_after,line)
    if indent_first: ppr+='<w:ind w:firstLine="%d"/>'%indent_first
    ppr+='<w:jc w:val="%s"/></w:pPr>'%align
    return '<w:p>%s%s</w:p>'%(ppr,run(text,bold=bold,size=size))
def page_break(): return '<w:p><w:r><w:br w:type="page"/></w:r></w:p>'
def empty_para(): return '<w:p><w:pPr><w:spacing w:after="0" w:line="360" w:lineRule="auto"/></w:pPr></w:p>'
def build_topic(t,is_first):
    parts=[]
    if not is_first: parts.append(page_break())
    parts.append(para("%d-MAVZU. %s"%(t["num"],t["title"].upper()),bold=True,size=30,align="center",indent_first=0,space_after=180,keep_next=True))
    parts.append(para("Reja:",bold=True,size=28,align="left",indent_first=0,space_after=60,keep_next=True))
    for i,r in enumerate(t["reja"],1): parts.append(para("%d. %s"%(i,r),size=28,align="left",indent_first=360,space_after=40))
    parts.append(empty_para())
    for idx,(head,paras) in enumerate(t["sections"],1):
        parts.append(para("%d. %s"%(idx,head),bold=True,size=28,align="left",indent_first=0,space_after=80,keep_next=True))
        for p in paras: parts.append(para(p,size=28,align="both",indent_first=709,space_after=120))
    return "".join(parts)
def build_document():
    body="".join(build_topic(t,i==0) for i,t in enumerate(TOPICS))
    sect='<w:sectPr><w:pgSz w:w="11906" w:h="16838"/><w:pgMar w:top="1134" w:right="850" w:bottom="1134" w:left="1701" w:header="708" w:footer="708" w:gutter="0"/><w:pgNumType w:start="1"/></w:sectPr>'
    return '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"><w:body>'+body+sect+'</w:body></w:document>'
CT='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/><Override PartName="/word/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"/><Override PartName="/docProps/core.xml" ContentType="application/vnd.openxmlformats-package.core-properties+xml"/><Override PartName="/docProps/app.xml" ContentType="application/vnd.openxmlformats-officedocument.extended-properties+xml"/></Types>'
RE='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/><Relationship Id="rId2" Type="http://schemas.openxmlformats.org/package/2006/relationships/metadata/core-properties" Target="docProps/core.xml"/><Relationship Id="rId3" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/extended-properties" Target="docProps/app.xml"/></Relationships>'
DR='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles" Target="styles.xml"/></Relationships>'
ST='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:docDefaults><w:rPrDefault><w:rPr><w:rFonts w:ascii="Times New Roman" w:hAnsi="Times New Roman" w:cs="Times New Roman"/><w:sz w:val="28"/><w:szCs w:val="28"/><w:lang w:val="uz-Latn-UZ"/></w:rPr></w:rPrDefault><w:pPrDefault><w:pPr><w:spacing w:line="360" w:lineRule="auto"/></w:pPr></w:pPrDefault></w:docDefaults><w:style w:type="paragraph" w:default="1" w:styleId="Normal"><w:name w:val="Normal"/><w:rPr><w:rFonts w:ascii="Times New Roman" w:hAnsi="Times New Roman" w:cs="Times New Roman"/><w:sz w:val="28"/><w:szCs w:val="28"/></w:rPr></w:style></w:styles>'
def cp():
    n=datetime.datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ")
    return '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<cp:coreProperties xmlns:cp="http://schemas.openxmlformats.org/package/2006/metadata/core-properties" xmlns:dc="http://purl.org/dc/elements/1.1/" xmlns:dcterms="http://purl.org/dc/terms/" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"><dc:title>Jismoniy tarbiya - Mustaqil ishlar</dc:title><dc:creator>Konspekt</dc:creator><dcterms:created xsi:type="dcterms:W3CDTF">%s</dcterms:created><dcterms:modified xsi:type="dcterms:W3CDTF">%s</dcterms:modified></cp:coreProperties>'%(n,n)
AP='<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<Properties xmlns="http://schemas.openxmlformats.org/officeDocument/2006/extended-properties"><Application>Konspekt</Application></Properties>'
def write_docx(path):
    with zipfile.ZipFile(path,"w",zipfile.ZIP_DEFLATED) as z:
        z.writestr("[Content_Types].xml",CT); z.writestr("_rels/.rels",RE)
        z.writestr("word/document.xml",build_document()); z.writestr("word/_rels/document.xml.rels",DR)
        z.writestr("word/styles.xml",ST); z.writestr("docProps/core.xml",cp()); z.writestr("docProps/app.xml",AP)
    print("OK:",path,"|",len(TOPICS),"mavzu")

TOPICS.append({"num":1,"title":"Talabalarning umumiy jismoniy tayyorgarligini o'rganish","reja":["Umumiy jismoniy tayyorgarlik tushunchasi va ahamiyati.","Talabalarning jismoniy tayyorgarlik darajasini aniqlash usullari.","Jismoniy sifatlarni o'rganish va baholash mezonlari.","Mashg'ulot rejasini ishlab chiqish."],"sections":[("Umumiy jismoniy tayyorgarlik tushunchasi va ahamiyati",["Umumiy jismoniy tayyorgarlik (UJT) — bu inson organizmining har tomonlama jismoniy rivojlanganlik darajasi va uning asosiy harakat sifatlarining (kuch, tezlik, chidamlilik, epchillik, egiluvchanlik) muvofiq holatda bo'lishidir. UJT har qanday jismoniy faoliyat va sport turi uchun zamin yaratadi.","Talabalar uchun UJT alohida ahamiyatga ega: u sog'liqni mustahkamlaydi, ish qobiliyatini oshiradi, charchoqqa bardoshlikni rivojlantiradi va kasalliklardan saqlaydi. Umumiy jismoniy tayyorgarlikka ega bo'lgan talaba o'qish, mehnat va ijtimoiy faoliyatda muvaffaqiyatli bo'ladi.","UJT asosida maxsus jismoniy tayyorgarlik (MJT) shakllanadi. Yaxshi UJTsiz biror sport turi bo'yicha yuqori natijalarga erishish mumkin emas. Shuning uchun jismoniy tarbiya darslarida avval UJT mustahkamlanadi, keyin maxsus tayyorgarlik bosqichiga o'tiladi."]),("Talabalarning jismoniy tayyorgarlik darajasini aniqlash usullari",["Talabaning jismoniy tayyorgarlik darajasini aniqlash uchun nazorat normativlari (testlar) qo'llaniladi. Bular: 100m yugurish (tezlik), 1000-3000m yugurish (chidamlilik), uzunlikka sakrash (kuch va epchillik), tortilish va otjimaniya (kuch), gavda egiluvchanligi sinovi (egiluvchanlik).","Sinovlar standart sharoitlarda, professional usulda o'tkaziladi: avval qizdiruv, keyin asosiy sinov, keyin tiklanish. Har bir natija qayd etiladi va belgilangan normativlar bilan taqqoslanadi. Bu obyektiv baho berish imkonini beradi.","Sinovlar o'quv yili boshida (dastlabki diagnostika), o'rtasida (joriy nazorat) va oxirida (yakuniy baholash) o'tkaziladi. Natijalar dinamikasi talabaning rivojlanishini ko'rsatadi va mashg'ulot dasturini tuzatish uchun asos bo'ladi."]),("Jismoniy sifatlarni o'rganish va baholash mezonlari",["Har bir jismoniy sifat o'ziga xos test orqali o'lchanadi: kuch — tortilish soni, otjimaniya soni, dinamometr ko'rsatkichi; tezlik — 30m, 60m, 100m yugurish vaqti; chidamlilik — uzoq masofaga yugurish (1500m, 3000m); egiluvchanlik — gavda egilishi smda; epchillik — chelnok yugurish 4×10m.","Baholash mezonlari yosh va jinsga qarab belgilanadi: yigitlar va qizlar uchun normativlar farqlanadi. Har bir test uchun 'a'lo', 'yaxshi', 'qoniqarli' va 'qoniqarsiz' darajalari bor. Talaba o'z natijalarini norma bilan taqqoslab, kuchli va zaif tomonlarini biladi.","Komplekslar baho beradi: barcha sinovlar yig'indisi umumiy jismoniy tayyorgarlik darajasini aks ettiradi. Bir sifat boshqasi hisobiga to'ldirilmaydi — har bir sifat alohida rivojlantirilishi kerak. Bu uyg'un rivojlanishni ta'minlaydi."]),("Mashg'ulot rejasini ishlab chiqish",["Diagnostika natijalari asosida individual mashg'ulot rejasi tuziladi. Reja talabaning hozirgi darajasi, maqsadi va imkoniyatlarini hisobga oladi. Kuchsiz tomonlar uchun ko'proq mashqlar, kuchli tomonlar uchun esa qo'llab-quvvatlovchi yuklamalar belgilanadi.","Reja tarkibi: hafta jadvali (necha kun va qaysi yo'nalishda mashg'ulot), kunlik dasturi (qizdiruv, asosiy qism, tiklanish), mashqlar ro'yxati (har bir sifat uchun) va yuklamalar dinamikasi (asta-sekin oshirib boriladi).","Reja muntazam tahlil qilinadi va tuzatiladi: agar natijalar yaxshilanmasa, dastur o'zgartiriladi. Yuklamalar bosqichma-bosqich oshiriladi (10-15% har 2-3 haftada). Bu charchash va shikastlanishning oldini oladi va barqaror o'sishni ta'minlaydi."])],})

TOPICS.append({"num":2,"title":"Yengil atletika: uzoqqa yugurish","reja":["Uzoqqa yugurish tushunchasi va turlari.","Uzoqqa yugurish texnikasi.","Uzoqqa yugurishga tayyorgarlik usullari.","Tarmoqlanuvchi mashqlar va musobaqa qoidalari."],"sections":[("Uzoqqa yugurish tushunchasi va turlari",["Uzoqqa yugurish — yengil atletikaning eng qadimiy va ommaviy turlaridan biri. U sportchidan yuqori darajada chidamlilik, irodaviy fazilatlar va to'g'ri taktikani talab qiladi. Asosiy masofalar: 3000m, 5000m, 10000m, marafon (42,195km).","Masofalar bo'yicha tasnif: o'rta masofalar (800m, 1500m), uzoq masofalar (3000m-10000m), o'ta uzoq masofalar (yarim marafon, marafon). Har bir masofa o'ziga xos texnika va taktikani talab qiladi.","Uzoqqa yugurish nafaqat sport, balki sog'lomlashtirish vositasi sifatida ham keng qo'llaniladi. U yurak-qon tomir, nafas tizimini mustahkamlaydi, immunitetni oshiradi va stressni kamaytiradi. Talabalar uchun u eng qulay sog'lom turmush tarzi vositasidir."]),("Uzoqqa yugurish texnikasi",["Uzoqqa yugurish texnikasi sprint texnikasidan farq qiladi: harakatlar tejamli, ravon va uzoq vaqt davomida saqlanishi kerak. Asosiy elementlar: gavda holati, oyoq harakati, qo'l harakati va nafas olish.","Gavda biroz oldinga egilgan (5-7 daraja), bosh tik, ko'z 5-10 metr oldinga qaratilgan. Oyoq tovon yoki to'liq oyoq bilan yerga tegadi (sprintdan farqli). Qadam uzunligi va qadam chastotasi optimal nisbatda bo'ladi. Qo'llar tirsakdan 90 daraja bukilgan, erkin tebranadi.","Nafas olish — uzoqqa yugurishda hal qiluvchi: ritm bilan nafas olinadi (masalan, 2 qadam — nafas olish, 2 qadam — nafas chiqarish), burun va og'iz orqali birga olinadi. To'g'ri nafas olish chidamlilikni va kislorodni samarali yetkazib berishni ta'minlaydi."]),("Uzoqqa yugurishga tayyorgarlik usullari",["Tayyorgarlik tizimida turli usullar qo'llaniladi: uzluksiz usul (uzoq vaqt bir maromda yugurish — chidamlilik bazasini quradi), interval usul (yuklama va dam navbatlanadi — anaerob chidamlilik), takroriy usul (qisqa qattiq qismlarni takrorlash) va musobaqa usuli (real musobaqada).","Yuklama hajmi va intensivligi asta-sekin oshiriladi: dastlab uzoq, lekin sekin masofalar (chidamlilik bazasi), keyin tezlik elementlari qo'shiladi. Haftalik hajm bosqichma-bosqich oshiriladi, biroq 10% qoidasiga rioya qilinadi (har hafta 10% dan ortiq oshirilmaydi).","Tiklanish ham mashg'ulot bosqichi: yetarli uyqu (8-9 soat), to'g'ri ovqatlanish (uglevod va oqsillar), suv ichish, faol dam olish. Yengil yugurish va cho'zilish mushaklarning tezroq tiklanishini ta'minlaydi. Charchoq belgilarini tan olish va dam olish muhim."]),("Tarmoqlanuvchi mashqlar va musobaqa qoidalari",["Yordamchi mashqlar uzoqqa yugurish samaradorligini oshiradi: tepalikka yugurish (kuchni rivojlantiradi), sakrash mashqlari (oyoq kuchini), gavda mushaklari mashqlari (turg'unlik), suzish va velosiped (krost-trening — yuk almashtirish).","Musobaqa qoidalari: start (umumiy yoki mustaqil chiziqdan), trassa (stadion treki yoki yo'l), o'tib ketish (faqat tashqi tomondan), finish (gavda chiziqni kesib o'tishi). Falstart yoki o'tkir to'siq qilish chetlatilishga olib keladi.","Musobaqaga tayyorgarlik: 1-2 hafta oldin yuklamani kamaytirish (taper), 2-3 kun oldin yengil mashg'ulot, kechqurun yaxshi uxlash, ovqatlanishni boshqarish. Musobaqa kuni: yetarlicha qizdiruv, ruhiy sozlanish va taktik reja bilan ishtirok etish."])],})

TOPICS.append({"num":3,"title":"Sport o'yinlari: basketbol texnikasi va taktikasi","reja":["Basketbol o'yini va uning xususiyatlari.","Basketbolda asosiy texnik elementlar.","Basketbol taktikasi: hujum va himoya.","Basketbol qoidalari va musobaqa tartibi."],"sections":[("Basketbol o'yini va uning xususiyatlari",["Basketbol — XIX asr oxirida AQShda paydo bo'lgan jamoaviy sport o'yini. Uni 1891-yili Jeyms Neysmit ixtiro qilgan. Hozirda dunyoning eng ommaviy sport turlaridan biri, Olimpiya o'yinlari dasturiga kiritilgan.","O'yin maydoni 28×15 metr, ikki uchida 3,05m balandlikda savatlar joylashgan. Har bir jamoada 5 ta o'yinchi (jami 12 kishilik tarkibdan). O'yin to'rt davrdan iborat (har biri 10 daqiqa, NBA da 12 daqiqa). Maqsad — to'pni raqib savatiga kiritish va o'z savatini himoya qilish.","Basketbol o'yinchidan kuch, tezlik, epchillik, sakrash qobiliyati va texnik mahoratni talab qiladi. U intensiv o'yin: 40 daqiqa davomida o'yinchi katta hajmda harakat qiladi. Shuning uchun yaxshi jismoniy tayyorgarlik shart."]),("Basketbolda asosiy texnik elementlar",["Texnik elementlar bir necha guruhga bo'linadi: to'p bilan ishlash (driblling, dispetcherlik), to'p tashlash (savatga otish), himoyalanish va sakrash texnikasi. Har bir element alohida o'rganilib, keyin o'yinda qo'llaniladi.","Driblling — to'pni yerga urib harakatlanish: o'ng va chap qo'l bilan, gavdani himoya qilib, boshni ko'tarib (atrofga qarab) bajariladi. Tashlash — to'pni savatga yo'naltirish: turgan joydan, sakrab tashlash, daljiniyadan otish (3 ochkolik) va ostidan yoritish (lay-up).","Yana muhim elementlar: passing (sherigiga to'p uzatish — ko'krakdan, boshdan, polga urilib), rebound (to'pni qaytarib olish), bloklash (raqib tashlashini to'xtatish), pivoting (bir oyoq bilan aylanish). Bu texnikalar yuzlab marotaba mashq qilinadi."]),("Basketbol taktikasi: hujum va himoya",["Hujum taktikasi: tez hujum (jadal hujum — raqib himoyaga qaytmasdan tashlash), pozitsion hujum (ish-block, picking, screening kombinatsiyalari), individual hujum (yakka harakatlar), zonali hujum (zonalarni egallash). Har bir taktika muayyan vaziyatda samarali.","Himoya taktikasi: shaxsiy himoya (har bir himoyachi muayyan o'yinchini kuzatadi), zonali himoya (har bir himoyachi maydonning bir qismini himoya qiladi), aralash himoya (ikkala usulning kombinatsiyasi), pressing (raqibga doimiy bosim).","Taktik harakatlar mashg'ulotlarda mukammal o'rganiladi va o'yinda qo'llaniladi. Murabbiy o'yin davomida taktikani o'zgartirib turadi raqibga moslashish va bosimni boshqarish uchun. Muvaffaqiyatli jamoa hujum va himoya taktikalarini muvozanatda saqlaydi."]),("Basketbol qoidalari va musobaqa tartibi",["Asosiy qoidalar: o'yinchi to'p bilan yura olmaydi (faqat driblling), ikki qo'l bilan dribllang qilib bo'lgach yana driblling qilolmaydi (double dribble), 24 soniya ichida tashlash kerak (otish chegarasi), 3 soniyadan ortiq raqib zonasida turish mumkin emas (3 sekund qoidasi).","Ochkolar: oddiy tashlash 2 ochko, 3 ochkolik chiziqdan tashqaridan tashlash 3 ochko, jarima tashlashi 1 ochko. Foul (qoidabuzarlik) — raqibga jismonan ta'sir qilish. 5 ta foul olgan o'yinchi maydondan chiqariladi (NBA da 6 ta).","Musobaqa tartibi: chempionatlar (lig formatida), kuboklar (chiqarish tizimida), Olimpiada va Jahon chempionatlari. O'zbekiston basketbol federatsiyasi mahalliy va xalqaro musobaqalarni tashkil etadi. Talabalar universitet va shahar darajasidagi turnirlarda qatnashishi mumkin."])],})

TOPICS.append({"num":4,"title":"Pastki start texnikasi va maxsus yugurish mashqlari","reja":["Pastki start tushunchasi va ahamiyati.","Pastki start texnikasi va bosqichlari.","Maxsus yugurish mashqlari.","Yugurish mahoratini takomillashtirish."],"sections":[("Pastki start tushunchasi va ahamiyati",["Pastki start (low start) — sprint masofalarida (100m, 200m, 400m) qo'llaniladigan boshlang'ich pozitsiya. Uning maqsadi — startdan eng tez chiqib, maksimal tezlikni eng qisqa vaqtda olish. Pastki start sprint natijasiga sezilarli ta'sir qiladi.","Pastki start dunyoga 1888-yili amerikalik sprintchi Charlz Sherrill tomonidan kiritilgan. Avval u g'alati ko'rinardi, lekin tez orada barcha sprintchilar uni qabul qildi. Hozirgi paytda barcha rasmiy sprint musobaqalarida pastki start qo'llaniladi.","Pastki startning afzalligi: oyoqlar maksimal kuch bilan yerga tegadi, gavda oldinga harakat olish uchun optimal pozitsiyada turadi va birinchi qadamlar maksimal tezda bajariladi. To'g'ri texnika 0,1-0,2 soniyaga vaqtni qisqartirishi mumkin — bu sprintda muhim."]),("Pastki start texnikasi va bosqichlari",["Pastki start uchta buyruq asosida bajariladi: 'O'rinlarga!' ('On your marks!'), 'Diqqat!' ('Set!'), startovoy signal (otish yoki signal). Har bir buyruqdan keyin sportchi aniq harakatlarni bajaradi.","'O'rinlarga!' — sportchi start kolodkalariga (start blocks) o'rnashadi: kuchli oyoq oldinga, ikkinchi oyoq orqaga, qo'llar yerga, barmoq uchlari start chizig'ida, tizza pastdagi oyoq yerga tegadi. 'Diqqat!' — sportchi tizzasini ko'taradi, tos baland turadi (yelkadan biroz baland), yelkalar qo'llardan oldinda. Sportchi qotib, signalni kutadi.","Signal — sportchi to'satdan qo'llarini yerdan ko'taradi va oldingi oyoq bilan kolodkadan kuch bilan itariladi. Birinchi qadamlar qisqa va chastotali, gavda 30-45 daraja oldinga egilgan. Asta-sekin gavda tikkalanadi va qadam uzunligi oshadi (15-20m da to'liq tezlikka chiqiladi)."]),("Maxsus yugurish mashqlari",["Sprint texnikasini takomillashtirish uchun maxsus yugurish mashqlari (drill) bajariladi. Eng asosiylari: tizzani baland ko'tarib yugurish (high knees), tovonni dumbaga urib yugurish (butt kicks), qadamlash (skipping), to'g'ri oyoq bilan yugurish (straight leg run).","Bu mashqlar to'g'ri texnika elementlarini alohida-alohida o'rgatadi va mustahkamlaydi. Ular qizdiruv qismida 20-30m masofada bajariladi, 2-3 qaytadan. Mashqlar texnika talablariga qat'iy mos bajarilishi kerak — sifat miqdordan muhim.","Boshqa muhim mashqlar: pastdagi koladkadan boshlanish mashqi (start chiqishi), 30-60m sprint (tezlikni rivojlantirish), yuqorigi tezlikni saqlash (flying sprints), tepalikka yugurish (kuchni rivojlantirish). Bu mashqlar haftaning 2-3 kuni bajariladi."]),("Yugurish mahoratini takomillashtirish",["Texnikani takomillashtirish — uzluksiz jarayon. Hatto eng yuqori darajadagi sprintchilar ham doimo o'z texnikasini yaxshilashda. Asosiy yo'nalishlar: yugurish iqtisodiyligi (kamroq energiya bilan tezroq harakatlanish), qadam uzunligi va chastotasi optimal nisbati, harakatlarning aniqligi.","Video tahlil katta yordam beradi: sportchining yugurishi yozib olinadi va sekin tezlikda ko'riladi. Xatolar aniqlanadi: gavda holati, oyoq qo'yilishi, qo'l harakati. Murabbiy bilan birga tahlil qilinadi va tuzatish dasturi tuziladi.","Mahoratni takomillashtirish uchun katta hajmda mashq talab etiladi: minglab marotaba qadamlar bajarilishi kerak. Sabr-toqat va izchil mashqlar yuqori natijaga olib keladi. Texnika avtomatik darajaga yetganda, sportchi tezlik haqida o'ylamasdan, lekin uni samarali namoyon eta oladi."])],})

TOPICS.append({"num":5,"title":"Sport o'yinlari: voleybol texnikasi va taktikasi","reja":["Voleybol o'yini va uning xususiyatlari.","Voleybolda asosiy texnik elementlar.","Voleybol taktikasi: hujum va himoya tizimlari.","Voleybol qoidalari va musobaqa formati."],"sections":[("Voleybol o'yini va uning xususiyatlari",["Voleybol — 1895-yili AQShda Uilyam Morgan tomonidan ixtiro qilingan jamoaviy sport o'yini. U dunyoning eng ommaviy sport turlaridan biri, Olimpiya dasturida 1964-yildan beri mavjud. O'yin uchun maxsus apparat talab etilmaydi — bu uni qulay qiladi.","Maydon 18×9 metr, o'rtasida balandligi 2,43m (erkaklar) yoki 2,24m (ayollar) bo'lgan to'r joylashgan. Har bir jamoada 6 o'yinchi maydonda (jami 12 kishilik tarkibdan). To'p sport teridan tayyorlangan, 65-67 sm aylanmaga ega.","O'yin maqsadi — to'pni to'r ustidan raqib maydoniga tushirish va o'z maydonida tushishiga yo'l qo'ymaslik. Har bir jamoa to'pni 3 marta ura oladi (lekin bir o'yinchi ketma-ket 2 marta urolmaydi). Voleybol intensiv, dinamik o'yin — jismoniy va texnik tayyorgarlikni talab qiladi."]),("Voleybolda asosiy texnik elementlar",["Voleybolning asosiy texnik elementlari: podacha (servis — to'pni o'yinga kiritish), priem (qabul — pastki yoki ustki uzatma), peredacha (uzatma sherigiga), napadayushiy udar (hujum urishi — spike), blok (himoya to'rda) va himoya (qabul tushayotgan to'pni).","Podacha turlari: pastki (oson), ustki to'g'ridan-to'g'ri (kuchli), planiruyushiy (havoda 'suzuvchi'), siljitma (jamping serve — sakrab podacha). Har bir turi alohida texnikani talab qiladi. Hujum urishi — voleybolning eng ko'rgazmali elementi: o'yinchi sakraydi va to'pni kuch bilan raqib maydoniga uradi.","Pastki uzatma (manchette) — qo'llarni qo'shib bilakdan to'pni qabul qilish. Ustki uzatma (parmaklar bilan) — barmoq uchlari bilan to'pni aniq sherikka uzatish. Bu ikki element voleybol asoslarini tashkil etadi va jamoaviy o'yinning poydevoridir. Bloklash — to'rda raqib hujumini to'xtatish: bir, ikki yoki uchta o'yinchi bloku."]),("Voleybol taktikasi: hujum va himoya tizimlari",["Hujum tizimi: 4-2 tizim (4 hujumchi, 2 uzatuvchi), 5-1 tizim (5 hujumchi, 1 uzatuvchi — eng mashhur), 6-0 tizim (har bir o'yinchi turli rolda bo'ladi). 5-1 tizim eng ko'p qo'llaniladi: yagona uzatuvchi barcha hujumlarni boshqaradi.","Himoya tizimlari: 6-0 himoya (barcha o'yinchilar maydon orqasida), 5-1 himoya (libero markazda), 6-up va 6-back tizimlari. Libero — maxsus himoyachi rol bo'lib, u faqat orqa qatorda o'ynaydi va boshqa formada (rangda) bo'ladi.","Taktik kombinatsiyalar: bystraya peredacha (tez uzatma — quick), kreston (cross), peredacha pipe va boshqalar. Murabbiy raqibni o'rganib, tegishli taktikani tanlaydi va o'yin davomida o'zgartiradi. Yaxshi taktika individual mahorat bilan birga g'alabani ta'minlaydi."]),("Voleybol qoidalari va musobaqa formati",["O'yin setlardan iborat: 5 sets formati (3 ta yutgan g'olib bo'ladi). Har bir set 25 ochkogacha (besh setda 15 ochkogacha) o'ynaladi, lekin 2 ochko farqi bilan g'alaba qozonish kerak. Bu 'rally point' tizimi — har bir o'yindan keyin ochko beriladi.","Asosiy qoidalar: 3 marta urish chegarasi, to'rga tegish taqiqlangan (faqat to'pni urganda), bloklash hisobga olinmaydi (3 urishdan birga emas), maydon chiziqlari ichidagi to'p o'ynalgan deb hisoblanadi (chiziqqa tegish ham). Aylantirish (rotation) — gol olingach, jamoa soat yo'nalishida bir pozitsiyaga ko'chadi.","Musobaqalar: Olimpiada, Jahon chempionati, Yevropa chempionati, Voleybol Millatlari ligasi (VNL). Klub futbol bilan barobar darajada — Italiya, Rossiya, Tureskaya ligalari kuchli. Plyaj voleyboli (2×2) ham keng tarqalgan va Olimpiya dasturida bor."])],})

TOPICS.append({"num":6,"title":"Yuqori start texnikasi va taktikasi","reja":["Yuqori start tushunchasi va qo'llanilishi.","Yuqori start texnikasi.","Yuqori start ishlatiladigan masofalar.","Start taktikasi va musobaqada qo'llash."],"sections":[("Yuqori start tushunchasi va qo'llanilishi",["Yuqori start (high start, standing start) — sportchi tik turgan holatdan boshlanadigan start turidir. U pastki startdan farqli ravishda kolodka talab qilmaydi va sportchi qaddini tutgan holda startga turadi. Bu start usuli o'rta va uzoq masofalar uchun xarakterli.","Yuqori start qulay va sodda — har qanday joyda (stadionda, yo'lda, krossda) qo'llanilishi mumkin. U sprintdagidek maksimal tezlikni talab qilmaydi, chunki uzoq masofada birinchi soniyalar emas, balki masofa bo'ylab tezlik va chidamlilik muhimdir.","Yuqori start jismoniy tarbiya darslarida talabalarga o'rgatiladi: u oddiy va xavfsiz, qo'shimcha jihozlar talab qilmaydi. Talabalar yengil atletikaning asosiy mashqlarini bajarishda yuqori startdan foydalanadilar."]),("Yuqori start texnikasi",["Yuqori start ham uch buyruqdan iborat: 'O'rinlarga!' — sportchi start chizig'iga keladi, kuchli oyog'ini oldinga, ikkinchisini orqaga qo'yadi (oyoqlar orasi taxminan yarim qadam). Gavda biroz oldinga egilgan, qo'llar erkin holatda.","'Diqqat!' buyrug'i (yoki to'g'ridan-to'g'ri startovaya signal — masofaga qarab) — sportchi gavdani yana oldinga egiltiradi, og'irlikni oldingi oyoqqa o'tkazadi va qo'llar harakat uchun tayyorlanadi (bir qo'l oldinda, ikkinchisi orqada).","Signal — sportchi oldingi oyoq bilan kuch bilan itarilib, ikkinchi oyog'ini ko'taradi va qadam tashlaydi. Birinchi qadamlar dadil, gavda asta-sekin tikkalanadi. 20-30 metrgacha sportchi to'liq yugurish ritmiga kiradi."]),("Yuqori start ishlatiladigan masofalar",["Yuqori start odatda quyidagi masofalarda qo'llaniladi: 800m va 1500m (o'rta masofalar), 3000m, 5000m va 10000m (uzoq masofalar), marafon va boshqa marafondagi masofalar, krossdagi yugurishlarda, estafetalarning 2-3-4 etablarida.","Sprintda (100m, 200m, 400m) yuqori start qo'llanilmaydi — chunki bu masofalarda boshlang'ich tezlanish hal qiluvchi va kolodkalardan foydalanish samaraliroq. Lekin maktabda yengil atletika darslarida talabalar 100m gacha ham yuqori startdan boshlashlari mumkin.","Sport o'yinlarida ham yuqori start kerak bo'ladi: o'yinchi to'pni qabul qilish yoki raqibga qarshi yugurishda yuqori startdan boshlanadi. Estafetalarda taqachining qo'lidan yog'och olib (rapid takeover) yuqori startdan tezlikka chiqiladi."]),("Start taktikasi va musobaqada qo'llash",["Yuqori startda taktika muhim: o'rta va uzoq masofalarda startda eng tez chiqish kerak emas — energiya saqlanishi kerak. Sportchi startdan keyin o'z tempini topadi va uni masofa bo'ylab saqlaydi. Birinchi 50-100 metrda joy egallashi muhim.","Musobaqada start pozitsiyasini tanlash ham strategik: ichki yo'lkalar qisqa (lekin egilish tor), tashqi yo'lkalar uzun (egilish keng). 800m da odatda raqobatchilarning kuchini ko'rib, ularning orqasida turish va o'sha sur'atda chopib ketish samarali.","Start xatolari: hayajondan haddan tashqari erta yugurishni boshlash (falstart), notog'ri pozitsiyada turish (muvozanatsiz), startovaya signalni kutmasdan harakat qilish. Bu xatolar mashq va tajribada bartaraf etiladi. Musobaqaga ruhiy tayyorgarlik ham start sifatiga ta'sir qiladi."])],})

TOPICS.append({"num":7,"title":"Sport o'yinlari: futbol texnikasi va taktikasi","reja":["Futbol o'yini va uning xususiyatlari.","Futbolda asosiy texnik elementlar.","Futbol taktikasi va o'yin tizimlari.","Futbol qoidalari va musobaqa tartibi."],"sections":[("Futbol o'yini va uning xususiyatlari",["Futbol — dunyoning eng ommaviy sport turi, milliarlab muxlislarga ega. U zamonaviy shaklda XIX asrda Angliyada shakllangan. 1904-yili FIFA tashkil etilgan. Olimpiya o'yinlari va to'rt yilda bir marta o'tkaziladigan FIFA Jahon kubogi eng nufuzli musobaqalardir.","Maydon 100-110×64-75 metr, ikki uchida 7,32×2,44m darvozalar joylashgan. Har bir jamoa 11 kishidan iborat (1 darvozabon va 10 maydon o'yinchisi). O'yin 90 daqiqa (ikki davr 45 daqiqadan, tanaffus 15 daqiqa). Maqsad — to'pni raqib darvozasiga kiritish.","Futbol jismoniy, texnik, taktik va ruhiy tomonlardan kompleks talab qiladi. O'yinchi 90 daqiqa davomida 9-13 km masofa bosadi, turli intensivlikda harakatlanadi. Texnik mahorat va taktik fikrlash hal qiluvchi rol o'ynaydi."]),("Futbolda asosiy texnik elementlar",["Asosiy texnik elementlar: to'pni qabul qilish va boshqarish (control), driblling (to'p bilan harakatlanish), uzatish (passing), urish (shooting), sakrash bilan urish (header), to'g'ri va shimoldan otish (cornerlar va aut), darvozabon texnikasi (gol oldida).","To'pni qabul qilish (first touch) — yaxshi futbolchining belgisi: oyoq, son, ko'krak yoki bosh bilan to'pni o'z nazoratiga olish. Bu birinchi tegishish keyingi harakatlarning sifatini belgilaydi. Driblling — yakka tartibda raqibni chetlab o'tish: tezlik, harakat o'zgarishi va finta (aldash) bilan.","Urish texnikasi: yon tomon (instep) — kuch va aniqlik uchun, taqim (toe-poke) — tez urish, tovon (heel) — kutilmagan urish, son ichida (chip) — uzun va aniq uzatish. Har bir urish texnikasi muayyan vaziyatda samarali. Uzatish: qisqa (oyoq ichidan), uzun (cho'kichi bilan), ko'tarilgan (lobbed)."]),("Futbol taktikasi va o'yin tizimlari",["Taktik tizimlar (formatsiyalar) raqamlar bilan ifodalanadi (himoya-yarim himoya-hujumchi): 4-4-2 (klassik balansli tizim), 4-3-3 (hujumkor, eng ko'p ishlatiladigan zamonaviy tizim), 4-2-3-1 (mustahkam, moslashuvchan), 3-5-2 (qanot tomonlari faol), 5-3-2 (himoyaviy).","Taktik elementlar: pressing (raqibga bosim — yuqori, o'rta yoki past pressing), counter-attack (jadal hujum — raqib hujum qilganda darhol javob), tiki-taka (Barselona uslubi — qisqa uzatmalar bilan to'p egaligi), parking the bus (himoyada o'rnashish — kuchsiz raqibga qarshi).","Murabbiy raqibni o'rganib, taktikani tanlaydi va o'yin davomida o'zgartiradi. Almashtirishlar (3 ta + 1 qo'shimcha vaqt uchun, 5 ta — pandemiya o'zgarishlaridan keyin) taktik vositalardan biridir. Yaxshi taktika individual mahorat bilan birgalikda g'alabani ta'minlaydi."]),("Futbol qoidalari va musobaqa tartibi",["Asosiy qoidalar: ofsayd (raqib darvozasidan oxirgi himoyachi orqasida turib to'p qabul qilish taqiqlanadi), qo'l bilan o'ynash (faqat darvozabon o'z jarima maydonida), qoidabuzarliklar (faul — sariq va qizil kartochkalar). Qizil kartochka olgan o'yinchi maydondan chiqariladi.","Standart vaziyatlar: erkin urish (free kick — to'g'ridan-to'g'ri va bilvosita), penalti (11m chiziqdan urish), korner (burchakdan urish), aut (yon chiziqdan tashlash). Bu vaziyatlar gol olishning muhim manbalari hisoblanadi.","Yirik musobaqalar: FIFA Jahon kubogi, UEFA Yevropa chempionati (Euro), Champions League, AFC Osiyo kubogi. O'zbekiston futbol assotsiatsiyasi mahalliy chempionat (Super liga, Pro liga) va xalqaro musobaqalarni o'tkazadi. Yoshlar uchun universitet va shahar darajasidagi turnirlar mavjud."])],})

TOPICS.append({"num":8,"title":"500m dan 1000m ga yugurish. Jismoniy sifatlar","reja":["O'rta masofalarga yugurish xususiyatlari.","500-1000m yugurish texnikasi.","Bu masofa uchun jismoniy sifatlar.","Tayyorgarlik va musobaqa taktikasi."],"sections":[("O'rta masofalarga yugurish xususiyatlari",["O'rta masofalar (500m, 800m, 1000m, 1500m) — sprint va uzoq masofalar oralig'idagi turdir. Ular sportchidan tezlik va chidamlilikning birgalikdagi rivojlanganligini talab qiladi. Bu masofalarda anaerob (kislorodsiz) va aerob (kislorodli) energetik tizimlar birga ishlaydi.","500m masofa qisqa o'rta masofa hisoblanadi: u taxminan 60-70 soniya davom etadi va asosan anaerob xarakterga ega. 800m esa o'rtacha 1:45-2:00 minutda yugiriladi. 1000m taxminan 2:15-2:40 minutda. Bu masofalarda maksimal kuch va to'g'ri taktika muhim.","O'rta masofalar yugurishi katta jismoniy va ruhiy bardoshlikni talab qiladi: oxirgi 100-200 metr juda og'ir kechadi (laktik kislota to'planishi sababli). Ushbu masofada g'olib bo'lish uchun sportchi nafaqat tez yugurishi, balki azob-uqubatga chidashi ham kerak."]),("500-1000m yugurish texnikasi",["O'rta masofa texnikasi sprintdan farq qiladi: tejamli, lekin kuchli. Gavda biroz oldinga egilgan (3-5 daraja), qadam uzunligi optimal (haddan tashqari uzun emas, qisqa emas), oyoq tovon-aralash yer bilan kontakt qiladi (heel-toe).","Qo'l harakati ritmik va qudratli: tirsakdan 90 daraja bukilgan, oldindan orqaga harakat (yon tomonga emas). Qo'l kuchi yuqori darajada — u oyoq harakatini boshqaradi. Yaxshi qo'l harakati yuqori tezlikni saqlashga yordam beradi.","Nafas olish — hal qiluvchi: 500m da nafas olish ritmi 2:1 (2 qadamga nafas olish, 1 qadamga chiqarish), 1000m da 3:2 yoki 2:2. Burun va og'iz birga ishlaydi. Charchaganda nafas chuqurroq va tezroq bo'ladi — buni boshqarish kerak."]),("Bu masofa uchun jismoniy sifatlar",["O'rta masofa yugiruvchisi uchun zarur sifatlar: tezlik chidamliligi (yuqori tezlikni uzoq saqlash), maksimal tezlik (sprint elementi), aerob va anaerob chidamlilik (energiya tizimlari), kuch chidamliligi (oyoq mushaklarini ishlash davomiyligi), ruhiy bardoshlik.","Ushbu sifatlarni rivojlantirish uchun maxsus mashqlar: tempo run (uzoq tezlikda yugurish), interval mashqlari (200-400m segmentlar yuqori tezlikda), sprint mashqlari (60-100m), kuch mashqlari (gantellar, plyometriya), tepalikka yugurish.","Yo'lakdagi mashg'ulotlar muhim: stadionda 400m yo'lak bor, sportchi turli intensivlikda yuguradi. Aniq ko'rsatkichlarni o'lchaydi (vaqt, qadam) va dinamikani kuzatadi. GPS-soat va yurak urish monitorlari yuklamani boshqarish uchun foydali."]),("Tayyorgarlik va musobaqa taktikasi",["Yillik tayyorgarlik tsikli: 1) bazaviy davr (uzoq, sekin yugurish — chidamlilik bazasini quradi), 2) maxsus davr (tempo va interval), 3) tezlik davri (sprint elementlari), 4) musobaqa davri (poklik tezligi). Har bir davrning o'z maqsadi bor.","Musobaqa taktikasi: birinchi qadamlardan jadval bilan yugurish (graphic), 2/3 ga qadar joyni saqlash, oxirgi 200m da hujum (sprint finish). Ba'zi sportchilar oldinga chiqib boshqalar belgilash o'rnatadilar (front running), boshqalar esa orqada turib oxiriga sprint qiladilar.","Strategiyani raqib va o'z imkoniyatlariga moslab tanlash kerak. Tajriba va o'zlikni bilish muhim: o'zining kuchli tomonlari (sprint yoki chidamlilik) bo'yicha taktika tuziladi. Musobaqaga oldindan ruhiy tayyorgarlik (vizualizatsiya, ijobiy fikrlash) natijaga sezilarli ta'sir qiladi."])],})

TOPICS.append({"num":9,"title":"Jismoniy kuch va quvvatni oshirish qobiliyati","reja":["Kuch tushunchasi va uning turlari.","Kuchni rivojlantirish usullari.","Mushaklarning kuchini oshirish mashqlari.","Kuch mashqlarida xavfsizlik va metodika."],"sections":[("Kuch tushunchasi va uning turlari",["Kuch — bu mushaklarning tashqi qarshilikni yengish yoki unga qarshilik ko'rsatish qobiliyatidir. Kuch barcha jismoniy faoliyatning asosi: u yurish, yugurish, sakrash, ko'tarish va boshqa harakatlarning bajarilishini ta'minlaydi.","Kuchning bir necha turi mavjud: maksimal kuch (eng katta og'irlikni ko'tarish — og'ir atletika), tezkor kuch (qisqa vaqt ichida ko'p kuch — sprint, sakrash), kuch chidamliligi (uzoq vaqt davomida kuch ishlatish — voleybol, kurash) va portlovchi kuch (eng qisqa vaqtda maksimal kuch — to'pni urish, sakrash).","Har bir sport turi muayyan kuch turini talab qiladi: og'ir atletikachi maksimal kuchga, sprintchi tezkor kuchga, kurashchi kuch chidamliligiga e'tibor qaratadi. To'g'ri turdagi kuchni rivojlantirish — sport mahoratini oshirishning kalitidir."]),("Kuchni rivojlantirish usullari",["Kuchni rivojlantirishning asosiy usullari: 1) maksimal yuklamalar usuli (juda og'ir, kam takrorlash — 1-3 marta), 2) zo'r berish usuli (90% gacha og'ir og'irlik, 5-7 marta), 3) takroriy zo'r berish usuli (orta og'irlik, 8-12 marta — gipertrofiya), 4) izometrik usul (statik kuchlanish).","Plyometrik usul — portlovchi kuchni rivojlantirish: cho'qqilarga sakrash, kassani sakrab tushish va qaytadan ko'tarilish, depth jumps. Bu mashqlar mushak-pay reaksiyasini tezlashtiradi va sportchining sakrash qobiliyatini oshiradi.","Yuklama parametrlari muhim: og'irlik (necha foiz maksimal og'irlikdan), takrorlar soni (sets va reps), to'plamlar oralig'idagi dam (1-5 daqiqa), mashg'ulot chastotasi (hafta nechta marta). Bu parametrlar maqsadga qarab o'zgaradi."]),("Mushaklarning kuchini oshirish mashqlari",["Asosiy kuch mashqlari (compound exercises): otjimaniya (push-up — ko'krak), tortilish (pull-up — orqa), squat (cho'kib turish — oyoq), deadlift (yer dan ko'tarish — orqa va oyoq), bench press (ko'krak), shoulder press (yelka). Bu mashqlar bir necha mushak guruhini bir vaqtda ishlatadi.","O'z tana og'irligi bilan mashqlar: otjimaniya, tortilish, squat, plank (gavdaning markazini mustahkamlash — core), lunge (oldinga qadam bilan cho'kib turish), burpee (kompleks mashq). Bu mashqlar har joyda bajariladi va jihoz talab qilmaydi.","Og'irlik bilan mashqlar: gantellar (dumbbells), shtanga (barbell), kettlebells, qarshilik tasmalari (resistance bands), trenajyorlar. Og'irlik bosqichma-bosqich oshiriladi (progressive overload) — bu uzluksiz o'sishni ta'minlaydi. To'g'ri texnika og'irlikdan muhimroq."]),("Kuch mashqlarida xavfsizlik va metodika",["Kuch mashqlarida xavfsizlik birinchi o'rinda: to'g'ri texnika (avval engil og'irlik bilan o'rganish), yetarli qizdiruv (10-15 daqiqa — mushaklarni issiq qilish), to'g'ri nafas olish (zo'r berishda nafas chiqarish), spotter (og'ir og'irliklarda yordamchi) — bularsiz shikastlanish xavfi yuqori.","Mashg'ulot tuzilmasi: qizdiruv (5-10 daqiqa kardio + dinamik cho'zilish), asosiy qism (asosiy mashqlar, eng katta mushaklar oldin), izolyatsiyalovchi mashqlar (alohida mushaklar), tiklanish (statik cho'zilish). Bir mushak guruhi haftada 2-3 marta ishlatiladi (orasidagi 48-72 soat dam).","Tiklanish mashqdan kam emas: kuch mashqlaridan keyin mushaklar yiriklashadi va kuchayadi (faqat dam olganda). Yetarli uyqu (8 soat), oqsilga boy ovqat (1,6-2,2g/kg tana og'irligi), ko'p suv ichish va stressni boshqarish. Haddan tashqari mashq overtraining ga olib keladi va natijalarni pasaytiradi."])],})

TOPICS.append({"num":10,"title":"Sport o'yinlari: futbol — ikki tomonga o'yin","reja":["Ikki tomonga o'yin tushunchasi va maqsadi.","Mashg'ulot va o'quv o'yini tashkili.","O'yin davomida texnikani qo'llash.","Jamoaviy o'zaro munosabat va taktika."],"sections":[("Ikki tomonga o'yin tushunchasi va maqsadi",["Ikki tomonga o'yin (scrimmage, two-way game) — futbol mashg'ulotidagi muhim qism bo'lib, bunda ikki jamoa real o'yin sharoitlarida o'ynaydi. Lekin bu rasmiy musobaqa emas — o'qitish va tayyorgarlik maqsadida o'tkaziladi.","Maqsadi: o'rganilgan texnik va taktik elementlarni amaliyotda qo'llash, jamoaviy hamkorlikni shakllantirish, real musobaqa bosimiga ko'nikish, jismoniy va ruhiy chidamlilikni rivojlantirish, o'yinchilarning bilim darajasini baholash. Bu o'yin haqiqiy musobaqa va alohida mashqlar orasidagi 'ko'prik'.",", Ikki tomonga o'yin har bir mashg'ulotning oxirgi qismida o'tkaziladi: avval qizdiruv va texnik mashqlar, keyin taktik mashqlar, oxirida 20-40 daqiqa o'yin. O'yin oddiy (yengillashtirilgan qoidalar bilan) yoki shartli (ma'lum cheklovlar bilan) bo'lishi mumkin."]),("Mashg'ulot va o'quv o'yini tashkili",["O'quv o'yinining shakli mashg'ulot maqsadiga qarab o'zgaradi: o'lcham (3×3, 5×5, 7×7, 11×11), maydon o'lchami (kichik, o'rta, katta), o'yin davomiyligi (15-30 daqiqa), maxsus qoidalar (faqat 2 tegishish, faqat oyoq ichidan urish, vaqt cheklov ozod harakat).","Kichik o'yinlar (small-sided games — 4×4, 5×5) ko'p afzalliklarga ega: har bir o'yinchi to'pga ko'p tegadi, qarorlar tez qabul qilinadi, intensivlik yuqori, jismoniy va texnik tomonlar bir vaqtda rivojlanadi. Zamonaviy futbol mashg'ulotida small-sided games asosiy o'rin tutadi.","Hakam vazifasini murabbiy yoki yordamchi bajaradi. U nafaqat qoidabuzarlikni nazorat qiladi, balki o'yinchilarga ko'rsatma beradi (real vaqtda), xatolarni qayd qiladi va tahlil uchun saqlaydi. Murabbiy mashg'ulot maqsadini eslab tursin va kerak bo'lganda o'yinni to'xtatib, vaziyatni tushuntiradi."]),("O'yin davomida texnikani qo'llash",["O'quv o'yinining asosiy maqsadi — alohida o'rganilgan texnikani real o'yinda qo'llash. Masalan, qabul qilish texnikasi mashqlanganida, o'yinda to'pni qabul qilish vaziyatlariga e'tibor beriladi. O'yinchi nafaqat to'pni boshqarsa, balki keyingi harakatga tayyor bo'lsin.","Texnikani o'yinda qo'llash mashqdan ko'ra qiyinroq: raqib qarshilik ko'rsatadi, vaqt cheklov, ruhiy bosim. Birinchi marta texnika o'yinda buziladi — bu tabiiy. Mashqlar orqali u asta-sekin avtomatlashadi. Sabr-toqat va ko'p takrorlash kerak.","Murabbiy o'yindan keyin tahlil o'tkazadi: qaysi vaziyatlarda texnika to'g'ri qo'llanildi, qaysi vaziyatlarda xato bo'ldi. Video yozuvi katta yordam beradi — o'yinchi o'zini tashqaridan ko'radi. Xatolar muhokama qilinadi va keyingi mashg'ulotda yana mashqlanadi."]),("Jamoaviy o'zaro munosabat va taktika",["Ikki tomonga o'yinning muhim qismi — jamoaviy hamkorlikni shakllantirish. O'yinchilar bir-birini tushunishni, signal almashishni va birgalikda harakat qilishni o'rganadilar. Yaxshi jamoa — bu avtomatik aloqa va o'zaro qo'llab-quvvatlash.","Taktik elementlar o'yinda mashq qilinadi: pressing (raqibga bosim), kombinatsiyalar (ikki-uch o'yinchi birgalikda), set pieces (standart vaziyatlar — burchak, jarima), o'yin tempini boshqarish (tezlash yoki sekinlash). Murabbiy turli vaziyatlarda turli taktikani sinaydi.","Pozitsiyaviy intizom muhim: har bir o'yinchi o'z roli va vazifasini biladi va bajaradi. Lekin ijodiy yondashuv ham kerak — qattiq qoidalarga ko'r-ko'rona amal qilish o'yinni mexanikalashtiradi. Yaxshi jamoa — bu intizom va ijodning to'g'ri muvozanati."])],})

TOPICS.append({"num":11,"title":"Badminton sport o'yinlarini rejalashtirishni o'rganish","reja":["Badminton o'yini va uning xususiyatlari.","Badmintonda asosiy texnik elementlar.","Badminton mashg'ulot rejasini tuzish.","Badminton qoidalari va musobaqa formati."],"sections":[("Badminton o'yini va uning xususiyatlari",["Badminton — raketka va voldon (shuttlecock) bilan o'ynaladigan sport o'yini. U Hindistonda paydo bo'lgan, hozirda Olimpiya o'yinlari dasturida (1992-yildan beri). Osiyo mamlakatlari (Xitoy, Indoneziya, Malayziya, Janubiy Koreya) bu sport sohasida yetakchi.","Maydon 13,4×6,1m (juftlik uchun) yoki 5,18m (yakka uchun). O'rtasida balandligi 1,55m to'r. O'yin yopiq zalda o'tkaziladi (chunki shuttlecock shamoldan ta'sirlanadi). Raketka yengil (80-100g), simli to'rli, voldon esa tabiiy patdan tayyorlangan.","Badminton — eng tez sport turlaridan biri: shuttlecock 400 km/soat tezligida ucha oladi. O'yinchidan tezlik, epchillik, reaksiya va chidamlilikning yuqori darajasi talab etiladi. Badminton uchun maxsus jismoniy tayyorgarlik kerak — ayniqsa qanot kuchi, oyoq harakatchanligi va kor mushaklari."]),("Badmintonda asosiy texnik elementlar",["Texnik elementlar: podacha (servis — pastdan, faqat bel chizig'idan past), klir (clear — uzoq tepaga otish), drop (qisqa, to'rga yaqin tushish), smash (kuchli, pastga otish — eng samarali hujum zarbi), drayv (drive — to'g'ridan-to'g'ri parallel uchirish).","Raketkani ushlash usullari: forehand grip (asosiy ushlash — qo'lqop tutgandek), backhand grip (orqa qo'l ushlash — bosh barmoq raketka tutqichida), universal grip (ikki turning kombinatsiyasi). Raketkani to'g'ri ushlash zarbalarning kuchi va aniqligini belgilaydi.","Oyoq harakati (footwork) — badmintonda hal qiluvchi: lunge (o'tib qadamlash), shuffle (yon qadamlar), recovery step (orqaga qaytish). O'yinchi maydon bo'ylab tez harakat qilishi kerak. Yaxshi footworksiz texnika foydasi yo'q — voldonni to'g'ri pozitsiyada urish kerak."]),("Badminton mashg'ulot rejasini tuzish",["Yillik mashg'ulot rejasi: bazaviy davr (chidamlilik va kuch — 4-6 hafta), maxsus tayyorgarlik (texnika va taktika — 8-12 hafta), musobaqa davri (poklik shakliga kelish — 4-6 hafta), o'tish davri (faol dam — 2-4 hafta). Har davr o'z maqsadiga ega.","Haftalik reja (musobaqa davrida): 4-6 mashg'ulot. Mazmuni: texnik mashqlar (har kuni — zarbalarni mashq qilish), taktik o'yin (haftada 2-3 marta — to'liq o'yin yoki 50% tempda mashq), jismoniy tayyorgarlik (haftada 2 kun — kuch va kardio), tiklanish (1-2 kun).","Kunlik mashg'ulot tuzilmasi: qizdiruv (15-20 daqiqa — yengil yugurish, dinamik cho'zilish, raketka bilan engil zarbalar), asosiy qism (60-90 daqiqa — texnik mashqlar, taktik o'yin, jismoniy mashqlar), tiklanish (10-15 daqiqa — sekin cho'zilish, suv ichish). Yuklama bosqichma-bosqich oshiriladi."]),("Badminton qoidalari va musobaqa formati",["Asosiy qoidalar: voldon yer ga tushgach, ochko olinadi (rally point system); jamoa yutqizgan ochkodan keyin podacha o'zgaradi; podacha bel ostidan urilishi kerak (bel chizig'idan past); voldon to'rga tegishi mumkin (qoidabuzarlik emas), lekin to'r yoki o'yinchi tana orqali to'rning narigi tomoniga o'tishi taqiqlangan.","Setlar 21 ochkogacha o'ynaladi (eski 15 sistemasi 2006-yili o'zgarib, hozir 21 ochkoga). Setlar soni: ko'pi 3 dan 2 ga (best of three). Tenglikda — 30 ochkoga qadar (29-29 da kim oldin 30 ga yetsa). Ushbu format o'yinni dinamik va qiziqarli qiladi.","Musobaqa formatlari: yakka (singles — yigitlar va qizlar), juftlik (doubles — erkak juftliklari, ayol juftliklari, aralash juft). Eng nufuzli musobaqalar: Olimpiada, Jahon chempionati, Thomas/Uber kuboklari, BWF World Tour. O'zbekiston badminton federatsiyasi mahalliy turnirlarni va xalqaro turnirlarda ishtirok etishni tashkil etadi."])],})

TOPICS.append({"num":12,"title":"Maxsus jismoniy harakatlar, harakatli o'yinlar","reja":["Maxsus jismoniy harakatlar tushunchasi.","Harakatli o'yinlar va ularning ahamiyati.","Mashg'ulot va dars uchun harakatli o'yinlar.","Harakatli o'yinlarni tashkil etish metodikasi."],"sections":[("Maxsus jismoniy harakatlar tushunchasi",["Maxsus jismoniy harakatlar — muayyan sport turi yoki jismoniy faoliyat uchun zarur bo'lgan harakatlar majmuasidir. Ular umumiy jismoniy harakatlardan farqli ravishda aniq sport faoliyatining talablariga moslashtirilgan va uning samaradorligini oshiradi.","Maxsus harakatlar yangi mushak guruhlarini, koordinatsiyani va sport-texnik mahoratni rivojlantiradi. Masalan, futbolchi uchun zarur maxsus harakatlar: yon qadamlar, orqaga yugurish, to'piq harakatchanligi, sakrash. Voleybolchi uchun: vertikal sakrash, qol kuchi, tana aylanishi.","Maxsus harakatlar muvaffaqiyatining sababi — ular real sport vaziyatlarini imitatsiya qiladi. Sportchi nafaqat jismoniy sifatlarni rivojlantiradi, balki ularni o'z sport turida samarali qo'llashni o'rganadi. Bu UJTdan MJT ga o'tishning muhim bo'g'inidir."]),("Harakatli o'yinlar va ularning ahamiyati",["Harakatli o'yinlar — bolalar va talabalarni jismoniy faollikka jalb qiluvchi qoidalarga asoslangan o'yinlardir. Ular jismoniy tarbiyada va sportda muhim rol o'ynaydi: ular ko'ngilochar, tarbiyaviy va sog'lomlashtirish vositasi sifatida ishlaydi.","Harakatli o'yinlarning ahamiyati: jismoniy sifatlarni (tezlik, epchillik, kuch, chidamlilik) ko'ngilli shaklda rivojlantiradi, jamoaviylik va o'zaro yordamni tarbiyalaydi, ijodiy fikrlashni rivojlantiradi, ijobiy emotsional fonni yaratadi va sport faoliyatiga qiziqishni shakllantiradi.","Harakatli o'yinlar bolalar uchun ayniqsa muhim: ular o'yin shaklida rivojlanadi va o'rganadi. Ammo kattalar uchun ham foydali — monoton mashqlardan dam beradi va motivatsiyani saqlaydi. Talabalar darslarida harakatli o'yinlar mashg'ulotni qiziqarli qiladi."]),("Mashg'ulot va dars uchun harakatli o'yinlar",["Estafetalar — eng ommaviy harakatli o'yinlar: ikki yoki ko'p jamoa o'yinchilari navbatma-navbat masofani bosib o'tadi va shu jamoaning g'olib bo'lishini ta'minlaydi. Estafetalar yengil atletika, suzish, akrobatika va boshqa elementlarni o'z ichiga olishi mumkin.","To'pli o'yinlar: 'O'tib o'tish' (passing), 'Bosib olish' (capture the flag), 'Pioneerball' (voleybolning soddalashtirilgan varianti), 'Vibibol' va boshqalar. Bular sport o'yinlariga tayyorlash va texnik elementlarni qiziqarli mashq qilish vositasidir.","Tutush o'yinlari ('Salki'): bir o'yinchi qolganlarni tutmoqchi, ushlanganlar 'qotib qoladi' yoki o'rin o'zgartiradi. Bu o'yinlar tezlik va epchillikni rivojlantiradi. Yana qiziqarli: 'Qora-oq', 'Ovchi va o'rdaklar', 'Aniq otish' (to'pni nishonlangan joyga tashlash)."]),("Harakatli o'yinlarni tashkil etish metodikasi",["Harakatli o'yinlarni tashkil etish bosqichlari: 1) o'yin maqsadini aniqlash (nima rivojlantiriladi), 2) o'yinni tanlash (yosh va imkoniyatga mos), 3) joy va jihozlarni tayyorlash, 4) o'yin qoidalarini tushuntirish, 5) o'yinni o'tkazish va nazorat qilish, 6) yakuniy tahlil.","Qoidalarni tushuntirish aniq va qisqa bo'lishi kerak. O'yin boshlanishidan oldin: nima qilish kerak (maqsad), qanday qoidalar bor (taqiqlangan harakatlar), qanday yutish/yutqizish, xavfsizlik talablari. Kerak bo'lsa, harakatlarni ko'rsatib namoyish qilish.","O'yin davomida: hammaning ishtirokini ta'minlash, qoidabuzarlikni nazorat qilish, xavfsizlikni saqlash, ko'tarinki kayfiyatni qo'llab-quvvatlash. O'yin oxirida: yutuqlarni e'tirof etish, tahlil o'tkazish (nima yaxshi, nima yaxshilanish kerak), keyingi o'yin uchun rejani belgilash."])],})

TOPICS.append({"num":13,"title":"Gimnastika va akrobatika mashqlari","reja":["Gimnastika va akrobatika tushunchasi.","Gimnastik mashqlar turlari.","Akrobatik elementlar va ularning bajarilishi.","Mashqlarni xavfsiz bajarish va sug'urta."],"sections":[("Gimnastika va akrobatika tushunchasi",["Gimnastika — koordinatsiya, kuch, egiluvchanlik va estetik mahorat asosida bajariladigan jismoniy mashqlar tizimi. U Qadimgi Yunonistonda paydo bo'lgan, hozirda Olimpiya o'yinlari dasturining muhim qismi. Sport gimnastikasi, badiiy gimnastika va akrobatika asosiy yo'nalishlar.","Akrobatika — gimnastikaning bo'limi bo'lib, gavda turli xil burilishlari, sakrashlari, parvozlari va dinamik harakatlardan iborat. U yakka, juft yoki guruhda bajariladi. Akrobatika nafaqat sport, balki sirkda va san'atda ham qo'llaniladi.","Gimnastika va akrobatika ko'p sohalarda foydalanadi: jismoniy tarbiya darslari, sportchi tayyorlash (asosiy bazaviy harakat ko'nikmalari), tibbiyot (reabilitatsiya), nogironlar uchun va keksa odamlar uchun adaptatsiyalashgan dasturlar. Ular har tomonlama jismoniy rivojlanishni ta'minlaydi."]),("Gimnastik mashqlar turlari",["Asosiy mashqlar guruhi: 1) umumrivojlantiruvchi mashqlar (ORM — boshlanish va isitish uchun), 2) qurol bilan mashqlar (gantellar, to'plar, tasmalar), 3) snaryadlarda mashqlar (turnik, brus, halqalar, kon, qaytishan kon), 4) yer ustidagi mashqlar (yog'och, gimnastik gilam).","Klassik gimnastik elementlar: oldinga va orqaga umbalov (forward/backward roll), 'qayichi' (handstand), 'tepa o'rta' (cartwheel), 'shpagat' (split), 'mostik' (bridge — orqaga eguilish). Bu elementlar gimnastikaning asosini tashkil etadi va keyingi murakkab elementlarga zamin yaratadi.",", Snaryadda mashqlar: turnikda tortilish, mayatnik tebranishlar, aylanish; brusda otish va o'tish elementlari; halqalarda kuch elementlari (krest); konda sakrashlar va aylanishlar. Har bir snaryad o'ziga xos mahorat va tayyorgarlikni talab qiladi."]),("Akrobatik elementlar va ularning bajarilishi",["Akrobatik elementlar darajalari bo'yicha: 1) oddiy (umbalovlar, mostik, shpagat — boshlang'ichlar uchun), 2) o'rta (qayichi, tepa o'rta, qayichi orqaga ko'tarilish), 3) yuqori (saltolar — oldinga, orqaga, yon tomonga; aylanishlar 360, 540, 720 daraja).","Bajarish texnikasi: har bir element o'z ketma-ketligida o'rganiladi — avval qismlar, keyin yaxlit harakat. Sportchi avval to'siqsiz (gilam ustida), keyin yumshoq tushish bilan (kursy mat), nihoyat to'liq mustaqil bajaradi. Sabr-toqat va ko'p takrorlash — kalit.","Murakkab elementlar: 'flik-flak' (orqaga sakrash qo'l bilan tepish), 'rondat' (yon umbalov-sakrash), 'salto orqaga shpagatda' (back tuck), 'iccion' (eyl). Ularni faqat tajribali murabbiy rahbarligida, sug'urta bilan o'rganish mumkin. Maxsus jihozlar (lonzha, batut) yordam beradi."]),("Mashqlarni xavfsiz bajarish va sug'urta",["Xavfsizlik talablari: yetarli qizdiruv (mushaklarni isitish), to'g'ri texnika (avval engil elementlar — keyin murakkab), mos kiyim va poyabzal (yoki yalang oyoq), gimnastik gilam yoki maxsus mat (zarbni yumshatish), tajribali murabbiy rahbarligi.","Sug'urta — gimnastikaning muhim qismi: murabbiy yoki sherik sportchini qo'llab-quvvatlaydi va yiqilishdan saqlaydi. Sug'urta usullari: ko'krak ostidan tutish (yiqilishni oldini olish), bel ortidan tutish (gavdani ushlab turish), aylanish davomida boshqarish.","Shikastlanishlardan saqlanish: hech qachon charchab turganda murakkab elementni bajarmang, hech qachon o'zingizdan kuch ortiq element urinib ko'rmang, har doim qizdiruvni o'tkazing, og'riq paydo bo'lsa — to'xtang. Akrobatika va gimnastika san'atdir — uni bosqichma-bosqich va xavfsiz egallash kerak."])],})

TOPICS.append({"num":14,"title":"Kuchni rivojlantirish","reja":["Kuchni rivojlantirishning ilmiy asoslari.","Kuch mashqlarining tasnifi.","Kuchni rivojlantirish metodikasi.","Yosh va jinsga ko'ra kuch tayyorgarligi."],"sections":[("Kuchni rivojlantirishning ilmiy asoslari",["Kuch — mushak qisqarishidan kelib chiqadi. Mushak qancha ko'p tola (volokno) ishlasa, shuncha ko'p kuch hosil bo'ladi. Yuklama ostida mushak tolalari mikroshikastlanadi va keyin tiklanish jarayonida yiriklashadi va kuchayadi (gipertrofiya).","Kuchning rivojlanishida ikki asosiy mexanizm: nervli adaptatsiya (boshlang'ich oylarda — miya mushakni samaraliroq ishlatishni o'rganadi) va mushak gipertrofiyasi (uzoq vaqt davomida — mushak hujayralari yiriklashadi). Ikkalasi birgalikda kuchning sezilarli o'sishini ta'minlaydi.","Mushak tolalarining ikki turi bor: tez (qisqaradigan, oq — fast-twitch — kuch va tezlik uchun) va sekin (qizil — slow-twitch — chidamlilik uchun). Kuchni rivojlantirish uchun asosan tez tolalar mashq qilinadi. Genetika ham rol o'ynaydi: sprintchilarda tez tolalar ko'p, marafonchilarda — sekin."]),("Kuch mashqlarining tasnifi",["Mashqlar mushaklarning ishlash xarakteriga ko'ra: izotonik (mushaklar uzunligi o'zgaradi — eng ko'p ishlatiladigan), izometrik (mushaklar uzunligi o'zgarmaydi — statik kuchlanish, masalan plank), izokinetik (doimiy tezlik bilan, maxsus trenajyorda).","Bajarish usuliga ko'ra: dinamik (harakat bilan — squat, bench press), statik (qotib turish — plank, wall sit), plyometrik (sakrashlar, portlovchi harakatlar — box jump, depth jump), izolyatsiyalovchi (bir mushak — bicep curl), kompleks (ko'p mushak — squat).","Yuklama vositasiga ko'ra: o'z tana og'irligi (otjimaniya, tortilish), ozod og'irlik (gantellar, shtanga), trenajyorlar (machines), qarshilik tasmalari (bands), tabiiy yuklama (suvda mashqlar, tepalikka chiqish). Har bir tur o'z afzalliklariga ega."]),("Kuchni rivojlantirish metodikasi",["Asosiy printsiplar: 1) progressiv yuklama (har 1-2 hafta og'irlik yoki takrorlar oshiriladi), 2) maxsuslik (sport turining talablariga moslash), 3) tiklanish (mushaklar 48-72 soat dam oladi), 4) variatsiya (har 4-6 hafta dasturni o'zgartirish — adaptatsiya uchun), 5) izchillik.","Yuklama parametrlari: maksimal kuch uchun — 1-5 takrorlash, og'irlik 85-100% maxdan, dam 3-5 daqiqa, 4-6 to'plam. Gipertrofiya uchun — 8-12 takrorlash, og'irlik 70-80%, dam 60-90 sekund, 3-4 to'plam. Kuch chidamliligi uchun — 15-25 takrorlash, og'irlik 50-65%, dam 30-60 sekund, 2-3 to'plam.","Mashg'ulot tuzilmasi: bo'lib yuklama (split routine — har kuni boshqa mushak guruhi: dushanba — ko'krak, seshanba — orqa, va h.k.) yoki to'liq tana (full body — har mashg'ulotda barcha mushaklar). Boshlang'ichlar uchun full body afzal — 3 marta haftada."]),("Yosh va jinsga ko'ra kuch tayyorgarligi",["Bolalar va o'smirlar (10-16 yosh): kuch mashqlari mumkin va foydali, lekin og'irlik kichik (o'z tana og'irligi yoki engil og'irlik), texnika eng muhim, mashqlar o'yin shaklida. 18 yoshgacha to'liq og'ir mashqlardan saqlanish (bo'g'inlar va suyaklarning rivojlanishi davom etmoqda).","Yoshlar (17-30 yosh): bu davr eng yuqori kuch potensialini rivojlantirish uchun optimal. Maksimal yuklamalar mumkin, gipertrofiya tez kechadi. Sport mahoratining cho'qqisi shu yoshlarda erishiladi.","Ayollar uchun kuch mashqlari: ayollarda testosteron darajasi past, shuning uchun mushak hajmi katta o'smaydi (ayollar ko'p kuch mashqlardan ham 'erkak gavda' olmaydilar — bu noto'g'ri tushuncha). Kuch mashqlari ayollar uchun ham foyda — metabolizmni oshiradi, suyaklarni mustahkamlaydi va figurani shakllantiradi."])],})

TOPICS.append({"num":15,"title":"Sport o'yinlari: futbol texnikasi mashqlari","reja":["Texnik mashqlarning ahamiyati.","To'p bilan ishlashning asosiy mashqlari.","Uzatish va urish mashqlari.","Mashqlarni tashkil etish va metodika."],"sections":[("Texnik mashqlarning ahamiyati",["Futbol texnikasi — yuqori darajadagi futbolchining poydevoridir. Hatto eng yaxshi taktika va jismoniy tayyorgarlik ham zaif texnika bilan natija bermaydi. Texnik mashqlar — texnikani shakllantirish, mustahkamlash va takomillashtirish uchun zarur vositadir.","Texnik mashqlar nafaqat yangi futbolchilar uchun, balki professionallar uchun ham muhim. Eng yaxshi futbolchilar (Messi, Ronaldu) har kuni soatlab texnikani mashq qiladilar. Aynan bu doimiy mashq ularni boshqalardan ajratib turadi.","Texnik mashqlar avtomatizmga olib keladi: futbolchi o'ylamasdan, intuitiv tarzda to'g'ri harakat qiladi. Bu o'yin davomida hal qiluvchi — chunki o'yin tezligi sababli o'ylab harakat qilishga vaqt yo'q. Avtomatizm minglab marotaba takrorlash natijasida shakllanadi."]),("To'p bilan ishlashning asosiy mashqlari",["Driblling mashqlari: konuslar (cones) orasidan o'tish (slalom), tezlikda driblling (yo'lakda 30-50m), turli oyoq qismlari bilan boshqarish (oyoq ichi, tashqarisi, soni), to'p bilan harakat o'zgarishi (cuts, turns), 'ziq-zaq' harakatlar.","To'pni qabul qilish (first touch) mashqlari: devorga urilib qaytadigan to'pni har xil qismlar bilan qabul qilish (oyoq, son, ko'krak, bosh), sherikdan kelayotgan uzatmani avval bir tegishish bilan boshqarish, qisqa pasdan keyin keyingi harakatga o'tish.","Boshqaruv mashqlari (juggling) — to'pni havoda saqlash: oyoq bilan, son bilan, bosh bilan, kombinatsiyada. Bu mashq to'pni 'his qilish' (touch) ni rivojlantiradi va to'pni nazorat qilish qobiliyatini oshiradi. Boshlang'ich uchun 5-10 takrorlash, malakali futbolchilar — yuzlab."]),("Uzatish va urish mashqlari",["Uzatish (passing) mashqlari: juftlikda turli masofada (5m, 10m, 20m) qisqa uzatmalar, uzun uzatmalar (oyoq tagi yoki son ichi bilan), uchta o'yinchi uchburchakda (pass, move and receive), to'rtta o'yinchi kvadratda (ko'p variantli kombinatsiyalar).","Urish (shooting) mashqlari: turgan to'pni darvozaga urish (oddiy va aniqlik mashqi), harakat ichida urish (driblling-keyin urish), volley (havoda turgan to'pni urish), header (sakrab-bosh bilan urish), penalti va erkin urishlar (free kicks).","Yana muhim mashqlar: 1×1 vaziyatlar (raqibni chetlab o'tish va urish), kross va finish (qanot tomondan markazga uzatish va birovning uzatmasidan urish), korner mashqlari (burchakdan kross va himoya). Real o'yin vaziyatlarini imitatsiya qilish texnikani amaliyotga yaqinlashtiradi."]),("Mashqlarni tashkil etish va metodika",["Mashqlarni tashkil etish printsiplari: oddiyfikr murakkabga, sekindan tezga, statikdan dinamikga, qarshiliksizdan qarshilik bilan. Yangi element avval engil sharoitda o'rganiladi, keyin asta-sekin sharoit murakkablashtiriladi.","Hajm va intensivlik: bir mashg'ulotda har element 3-5 ta to'plam, har to'plamda 8-15 takrorlash. Sifat miqdordan muhim — texnika to'g'ri bo'lmasa, takrorlash foyda bermaydi (faqat yomon odatni mustahkamlaydi). Charchaganda mashqni to'xtatish kerak.","Mashqdan keyin tahlil: video yozuvini ko'rish (xatolarni topish uchun), murabbiy bilan suhbat (tushuntirishlar va tavsiyalar), keyingi mashg'ulot uchun reja. Mukammallikka erishish jarayonidir — har kuni biroz yaxshilanish ko'p oylar va yillar davomida ulkan natijalarga olib keladi."])],})

